  const task = await createTask({ id: randomUUID(), status: 'todo', ...req.body });
  res.status(201).send({ task });
});

// Update task status
router.patch('/:taskId', async (req, res) => {
  const { taskId } = req.params;
  if (!['todo', 'done'].includes(req.body.status)) return sendError(res, 400, 'BadRequest', 'Invalid status');
  const task = await updateTaskStatus(taskId, req.body.status);
  res.send({ task });
});

// Get tasks by status
router.get('/', async (req, res) => {
  const { status } = req.query;
  if (!status || !['todo', 'done'].includes(status)) return sendError(res, 400, 'BadRequest', 'Invalid status filter');
  const tasks = await getTasksByStatus(status);
  res.send({ tasks });
});

