  db.tasks.push(task);
  return task;
};

exports.updateTaskStatus = function(taskId, newStatus) {
  const taskIndex = db.tasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) throw new Error('NotFound');
  db.tasks[taskIndex].status = newStatus;
  return db.tasks[taskIndex];
};

exports.getTasksByStatus = function(status) {
  return db.tasks.filter(task => task.status === status);
